UPDATE custom_field_def
SET description = 'Identifiant normalisé et stable du bien immobilier, utilisé comme nom de dossier. RÈGLE DE NORMALISATION : utiliser uniquement [ville]-[nom-de-rue], en minuscules, sans numéro de rue, sans code postal, sans accent. Le numéro et le code postal sont intentionnellement exclus car ils sont souvent absents ou dans un ordre variable selon les documents. Exemples : paris-oberkampf, nice-promenade-des-anglais, lyon-republique, bordeaux-cours-victor-hugo, marseille-canebiere. Si plusieurs biens sont dans la même ville sur la même rue, ajouter un discriminant minimal (ex: paris-oberkampf-3eme). IMPORTANT : tous les documents d''un même bien doivent produire TOUJOURS le même identifiant, quelle que soit la façon dont l''adresse est écrite sur le document.'
WHERE slug = 'adresse_bien';
